import{_ as o,o as a,c as e,a3 as l}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"📚 条目管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/knowledge-base/entry-management.md","filePath":"user-guide/tools/knowledge-base/entry-management.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/knowledge-base/entry-management.md"};function i(n,t,d,s,h,u){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="📚-条目管理" tabindex="-1">📚 条目管理 <a class="header-anchor" href="#📚-条目管理" aria-label="Permalink to &quot;📚 条目管理&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>条目（CAIU）是知识库的基本单元，每个条目包含标题、内容、标签和元数据。&quot;条目管理&quot;就是对这些知识卡片进行增删改查、批量操作和分类组织的工作。</p><div class="tip custom-block"><p class="custom-block-title">核心场景</p><ul><li>你需要把零散的笔记整理为结构化的知识条目</li><li>想给条目打上标签，方便按主题分类检索</li><li>需要批量调整条目的优先级、启用状态</li><li>想快速找到特定标签或关键词的条目</li></ul></div><h2 id="条目列表" tabindex="-1">条目列表 <a class="header-anchor" href="#条目列表" aria-label="Permalink to &quot;条目列表&quot;">​</a></h2><p>进入知识库工作区后，左侧会展示当前知识库的<strong>条目列表</strong>，采用卡片布局展示。每个条目卡片显示：</p><table tabindex="0"><thead><tr><th>信息</th><th>说明</th></tr></thead><tbody><tr><td>标题（Key）</td><td>条目的唯一标识名称</td></tr><tr><td>摘要</td><td>内容前 100 字符的快照</td></tr><tr><td>标签</td><td>条目关联的标签名（最多展示 3 个，超出显示 &quot;+N&quot;）</td></tr><tr><td>优先级</td><td>非默认优先级（≠100）会以 <code>PX</code> 形式标注</td></tr><tr><td>向量化状态</td><td>通过闪电图标颜色标识：🟢 就绪 / 🟡 处理中 / 🔴 失败 / ⚪ 未向量化</td></tr><tr><td>启用开关</td><td>单条切换启用/禁用状态</td></tr><tr><td>Token 数</td><td>该条目累计消耗的 Token 数</td></tr><tr><td>更新时间</td><td>最后修改日期</td></tr></tbody></table><p>列表支持按 <strong>更新时间</strong>、<strong>标题（Key）</strong>、<strong>优先级</strong> 排序，以及升序/降序切换。</p><blockquote><p>TODO: 截图 - 条目列表界面，标注卡片布局的各元素</p></blockquote><h3 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h3><p>列表顶部的搜索框支持对条目标题（Key）和内容摘要进行<strong>关键词搜索</strong>，并触发后端语义检索返回更精确的结果。搜索时会显示匹配数量和搜索状态。</p><blockquote><p>TODO: 截图 - 搜索界面</p></blockquote><h2 id="添加条目" tabindex="-1">添加条目 <a class="header-anchor" href="#添加条目" aria-label="Permalink to &quot;添加条目&quot;">​</a></h2><h3 id="手动创建" tabindex="-1">手动创建 <a class="header-anchor" href="#手动创建" aria-label="Permalink to &quot;手动创建&quot;">​</a></h3><p>在工作区点击 <strong>添加条目</strong> 按钮，弹出编辑界面：</p><ol><li><strong>标题（Key）</strong>：必填，作为条目的唯一标识</li><li><strong>内容（Content）</strong>：可选的 Markdown 正文</li><li><strong>标签</strong>：可选的标签列表</li><li><strong>优先级</strong>：默认为 100</li></ol><p>创建完成后会自动选中新条目，方便继续编辑。</p><blockquote><p>TODO: 截图 - 添加条目弹窗，标注各输入区域</p></blockquote><h3 id="批量导入文件" tabindex="-1">批量导入文件 <a class="header-anchor" href="#批量导入文件" aria-label="Permalink to &quot;批量导入文件&quot;">​</a></h3><p>支持从本地导入文件，系统会自动处理：</p><p><strong>支持的导入方式：</strong></p><ul><li><strong>拖放文件</strong>：直接将文件拖到工作区</li><li><strong>选择文件</strong>：点击&quot;选择文件&quot;按钮</li><li><strong>批量导入</strong>：一次性选择多个文件</li></ul><p><strong>文件处理逻辑：</strong></p><ul><li>读取文件内容作为条目的 Content</li><li>自动提取第一个 Markdown 一级标题作为 Key（可在设置中关闭）</li><li>自动识别 <code>Tags: xxx</code> 或 <code>标签: xxx</code> 标记行添加标签（可在设置中关闭）</li><li>对内容相同的文件自动去重（可在设置中关闭）</li></ul><p><strong>导入结果反馈：</strong> 成功导入后，会显示：</p><ul><li>成功导入的条目数量</li><li>跳过的文件数（非文本格式）</li><li>去重过滤掉的文件数</li></ul><blockquote><p>TODO: 截图 - 导入文件后的结果反馈弹窗</p></blockquote><h2 id="编辑条目" tabindex="-1">编辑条目 <a class="header-anchor" href="#编辑条目" aria-label="Permalink to &quot;编辑条目&quot;">​</a></h2><h3 id="内容编辑" tabindex="-1">内容编辑 <a class="header-anchor" href="#内容编辑" aria-label="Permalink to &quot;内容编辑&quot;">​</a></h3><p>点击列表中的条目，右侧会展示完整的条目编辑器：</p><ul><li><strong>标题</strong>：可编辑条目的 Key</li><li><strong>正文</strong>：Markdown 编辑器（基于 RichCodeEditor），支持语法高亮和实时预览</li><li><strong>标签</strong>：带权重的标签管理器，支持添加/删除标签以及 AI 辅助生成</li><li><strong>优先级</strong>：调整检索权重（数值 0-999）</li><li><strong>启用开关</strong>：禁用后该条目不会出现在搜索结果中</li></ul><p>编辑采用<strong>自动保存</strong>机制：内容发生变化后约 800ms 自动触发保存，无需手动点击按钮。保存时系统会自动：</p><ol><li>计算新的内容哈希</li><li>更新元数据中的摘要和标签快照</li><li>如果开启了自动向量化，触发重新向量化</li></ol><p>条目头部会显示&quot;正在保存...&quot;或&quot;已保存 HH:mm:ss&quot;的状态指示。</p><blockquote><p>TODO: 截图 - 右侧条目编辑器，标注各编辑区域</p></blockquote><h3 id="ai-辅助标签生成" tabindex="-1">AI 辅助标签生成 <a class="header-anchor" href="#ai-辅助标签生成" aria-label="Permalink to &quot;AI 辅助标签生成&quot;">​</a></h3><p>在编辑条目时，可以点击 <strong>AI 生成</strong> 按钮，系统会调用已配置的 LLM 模型自动分析内容并推荐标签。生成逻辑包括：</p><ul><li>基于内容语义提取 3-5 个核心标签</li><li>每个标签附带权重（0.0~1.0）</li><li>优先使用已有的专业术语</li></ul><p>标签生成可以在 <strong>设置 &gt; 标签生成</strong> 中配置：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>启用 AI 标签生成</td><td>主开关</td></tr><tr><td>生成模型</td><td>指定用于标签生成的 LLM（建议轻量模型）</td></tr><tr><td>生成提示词</td><td>自定义提示词模板，使用 <code>{content}</code> 占位</td></tr><tr><td>温度</td><td>控制生成随机性（建议 0.3 以下）</td></tr></tbody></table><blockquote><p>TODO: 截图 - AI 标签生成结果展示</p></blockquote><h2 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h2><p>在工作区顶部可以进入<strong>条目管理</strong>模式（勾选模式），选中多个条目后进行批量操作。</p><h3 id="批量启用-禁用" tabindex="-1">批量启用/禁用 <a class="header-anchor" href="#批量启用-禁用" aria-label="Permalink to &quot;批量启用/禁用&quot;">​</a></h3><p>选中多个条目后，可以一键切换启用状态。禁用后的条目在搜索时不会出现，但保留内容和向量，随时可以重新启用。</p><p>适用场景：暂时不想让某些条目影响搜索结果，但不删除它们。</p><h3 id="批量更新向量" tabindex="-1">批量更新向量 <a class="header-anchor" href="#批量更新向量" aria-label="Permalink to &quot;批量更新向量&quot;">​</a></h3><p>选中多个条目后，可以批量触发向量化同步。</p><h3 id="批量-ai-标签生成" tabindex="-1">批量 AI 标签生成 <a class="header-anchor" href="#批量-ai-标签生成" aria-label="Permalink to &quot;批量 AI 标签生成&quot;">​</a></h3><p>选中多个条目后，可以批量调用 LLM 为条目<strong>补充标签</strong>或<strong>强制重生成</strong>。</p><h3 id="批量导出-删除" tabindex="-1">批量导出/删除 <a class="header-anchor" href="#批量导出-删除" aria-label="Permalink to &quot;批量导出/删除&quot;">​</a></h3><p>选中多个条目后，可以一次性导出或删除。删除操作会：</p><ol><li>删除条目原始数据（<code>entries/{entryId}.json</code>）</li><li>删除对应的向量文件（<code>vectors/{modelHash}/{entryId}.vec</code>）</li><li>从元数据索引中移除</li><li>从缓存中清除</li></ol><div class="warning custom-block"><p class="custom-block-title">删除不可逆</p><p>删除后的条目无法恢复。如果只是暂时不想使用，建议用&quot;禁用&quot;功能代替删除。</p></div><blockquote><p>TODO: 截图 - 批量操作模式，标注选中状态和操作按钮</p></blockquote><h2 id="标签管理" tabindex="-1">标签管理 <a class="header-anchor" href="#标签管理" aria-label="Permalink to &quot;标签管理&quot;">​</a></h2><h3 id="标签系统" tabindex="-1">标签系统 <a class="header-anchor" href="#标签系统" aria-label="Permalink to &quot;标签系统&quot;">​</a></h3><p>知识库采用<strong>带权重的标签系统</strong>（内部表示为 <code>{name: string, weight: number}</code>）。每个标签可以附带权重（0.0~1.0），权重越高在语义检索中的影响力越大。标签在 UI 中通过标签管理器进行添加、编辑权重和删除。</p><h3 id="全局标签池-tag-pool" tabindex="-1">全局标签池（Tag Pool） <a class="header-anchor" href="#全局标签池-tag-pool" aria-label="Permalink to &quot;全局标签池（Tag Pool）&quot;">​</a></h3><p>标签池是全局的基础设施：</p><ul><li><strong>跨库共享</strong>：同一名称的标签在不同知识库中共享同一个向量表示</li><li><strong>按模型隔离</strong>：标签的向量空间按 Embedding 模型隔离</li><li><strong>语义联想</strong>：标签本身也被向量化并建立索引，支持&quot;以标签找标签&quot;的语义搜索</li></ul><h3 id="标签池管理器" tabindex="-1">标签池管理器 <a class="header-anchor" href="#标签池管理器" aria-label="Permalink to &quot;标签池管理器&quot;">​</a></h3><p>在 <strong>设置 &gt; 标签池管理</strong> 中可以：</p><ul><li><strong>浏览</strong>：查看所有已发现的标签及其使用频率</li><li><strong>搜索</strong>：关键词搜索标签</li><li><strong>向量化</strong>：对未向量化的标签进行向量化</li><li><strong>清理</strong>：删除没有条目关联的孤立标签</li></ul><blockquote><p>TODO: 截图 - 标签池管理器，展示标签列表和操作按钮</p></blockquote><h3 id="已发现标签" tabindex="-1">已发现标签 <a class="header-anchor" href="#已发现标签" aria-label="Permalink to &quot;已发现标签&quot;">​</a></h3><p>系统会自动收集所有知识库中使用过的标签，在搜索时提供标签建议。标签统计信息显示在 <strong>统计</strong> 标签页，包括：</p><ul><li>标签总数</li><li>已向量化标签数</li><li>每个标签的使用频率</li><li>按使用频率排序的热门标签</li></ul><h2 id="导出知识库" tabindex="-1">导出知识库 <a class="header-anchor" href="#导出知识库" aria-label="Permalink to &quot;导出知识库&quot;">​</a></h2><p>支持将整个知识库导出为 JSON 文件：</p><ul><li><strong>格式</strong>：JSON</li><li><strong>内容</strong>：包含所有条目的完整数据和元数据</li><li><strong>文件名</strong>：自动生成为 <code>{知识库名称}_export_{日期}.json</code></li></ul><p>导出的文件可以用于备份、迁移到其他设备，或供外部工具处理。</p><h2 id="克隆知识库" tabindex="-1">克隆知识库 <a class="header-anchor" href="#克隆知识库" aria-label="Permalink to &quot;克隆知识库&quot;">​</a></h2><p>知识库支持克隆（复制）操作：</p><ul><li>自动命名：源库名称 + <code> (副本)</code>，如果重名则自动递增为 <code> (副本 2)</code></li><li>克隆内容：复制所有条目的原始数据和元数据</li><li>适用场景：基于现有知识库创建变体，或用于测试修改效果</li></ul><blockquote><p>TODO: 截图 - 克隆知识库的操作菜单</p></blockquote><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-条目标题-key-可以重复吗" tabindex="-1">Q：条目标题（Key）可以重复吗？ <a class="header-anchor" href="#q-条目标题-key-可以重复吗" aria-label="Permalink to &quot;Q：条目标题（Key）可以重复吗？&quot;">​</a></h3><p>同一个知识库中条目 Key 是<strong>唯一标识符</strong>，不可重复。如果导入时遇到重名条目，系统会将其视为更新操作而不是新建。</p><h3 id="q-条目启用的作用是什么" tabindex="-1">Q：条目启用的作用是什么？ <a class="header-anchor" href="#q-条目启用的作用是什么" aria-label="Permalink to &quot;Q：条目启用的作用是什么？&quot;">​</a></h3><p>禁用条目后，该条目不会出现在搜索结果中，但原始数据和向量文件都保留着。你可以随时重新启用。适合暂时隐藏某些条目而不丢失其向量化状态。</p><h3 id="q-标签为什么需要向量化" tabindex="-1">Q：标签为什么需要向量化？ <a class="header-anchor" href="#q-标签为什么需要向量化" aria-label="Permalink to &quot;Q：标签为什么需要向量化？&quot;">​</a></h3><p>标签向量化后，系统可以进行&quot;语义联想&quot;——比如&quot;React&quot;和&quot;Vue&quot;虽然字面不同，但在向量空间中距离较近，搜索时可以用标签找到概念上相关的内容。</p><h3 id="q-导入文件时自动提取的标题不对怎么办" tabindex="-1">Q：导入文件时自动提取的标题不对怎么办？ <a class="header-anchor" href="#q-导入文件时自动提取的标题不对怎么办" aria-label="Permalink to &quot;Q：导入文件时自动提取的标题不对怎么办？&quot;">​</a></h3><p>在 <strong>设置 &gt; 导入与预处理</strong> 中关闭&quot;导入时自动提取标题&quot;，然后自行编辑条目标题。</p><h3 id="q-为什么批量导入提示很多跳过" tabindex="-1">Q：为什么批量导入提示很多跳过？ <a class="header-anchor" href="#q-为什么批量导入提示很多跳过" aria-label="Permalink to &quot;Q：为什么批量导入提示很多跳过？&quot;">​</a></h3><p>可能原因：</p><ol><li>文件格式不被支持（只支持 <code>.md</code>、<code>.txt</code> 等文本格式）</li><li>开启了去重且文件内容与已有条目完全一致</li><li>文件内容为空</li></ol>',88)])])}const p=o(r,[["render",i]]);export{g as __pageData,p as default};
